<template><el-card><template #header>数据资产健康度</template><div class="two-col"><DataTable :data="rows"><el-table-column prop="assetName" label="资产" min-width="220"/><el-table-column v-for="c in cols" :key="c.p" :prop="c.p" :label="c.l"/></DataTable><el-card><template #header>评分维度雷达图</template><div ref="radar" class="chart"/></el-card></div></el-card></template>
<script setup lang="ts">import { onMounted, ref } from 'vue'; import * as echarts from 'echarts'; import { healthScores } from '@/mock/data'; import DataTable from '@/components/DataTable.vue'; const rows=ref(healthScores); const radar=ref<HTMLElement>(); const cols=[['authority','权威性'],['integrity','完整性'],['timeliness','时效性'],['consistency','一致性'],['traceability','可追溯性'],['retrieval','可检索性'],['contribution','使用贡献度'],['security','安全合规']].map(([p,l])=>({p,l})); onMounted(()=>echarts.init(radar.value!).setOption({radar:{indicator:cols.map(c=>({name:c.l,max:100}))},series:[{type:'radar',data:[{value:cols.map(c=>(rows.value[0] as any)[c.p]),name:rows.value[0].assetName}]}]}));</script>
